function myAlgorithm(id, grid, size) {
  const EMPTY = -1;
  const n = size * size;
  const k = Math.floor(size / 8);
  if (k <= 0) return [];

  const ownDist = new Int16Array(n);
  const enemyDist = new Int16Array(n);
  const nearestEnemyId = new Int16Array(n);
  ownDist.fill(-1);
  enemyDist.fill(-1);
  nearestEnemyId.fill(-1);

  const emptyNbr = new Int8Array(n);
  const ownNbr = new Int8Array(n);
  const enemyNbr = new Int8Array(n);

  const queue = new Int32Array(n);
  const queueMeta = new Int16Array(n);
  const ownSeeds = [];
  const enemySeeds = [];
  const enemySeedIds = [];

  let insideCount = 0;
  let emptyCount = 0;
  let myCount = 0;
  const enemyCounts = {};

  for (let r = 0; r < size; r++) {
    const row = grid[r];
    const base = r * size;
    for (let c = 0; c < size; c++) {
      const v = row[c];
      if (v === null) continue;
      insideCount++;
      const idx = base + c;
      if (v === EMPTY) {
        emptyCount++;
      } else if (v === id) {
        ownDist[idx] = 0;
        ownSeeds.push(idx);
        myCount++;
      } else {
        enemyDist[idx] = 0;
        nearestEnemyId[idx] = v;
        enemySeeds.push(idx);
        enemySeedIds.push(v);
        enemyCounts[v] = (enemyCounts[v] || 0) + 1;
      }
    }
  }

  if (ownSeeds.length === 0) return [];

  let biggestEnemy = -1;
  let biggestEnemyCount = 0;
  let totalEnemies = 0;
  for (const eid in enemyCounts) {
    totalEnemies += enemyCounts[eid];
    if (enemyCounts[eid] > biggestEnemyCount) {
      biggestEnemyCount = enemyCounts[eid];
      biggestEnemy = +eid;
    }
  }

  const reachable = [];
  let head = 0;
  let tail = 0;

  for (let i = 0; i < ownSeeds.length; i++) queue[tail++] = ownSeeds[i];
  while (head < tail) {
    const idx = queue[head++];
    const d = ownDist[idx];
    const r = (idx / size) | 0;
    const c = idx - r * size;

    if (r > 0) {
      const nidx = idx - size;
      if (ownDist[nidx] === -1 && grid[r - 1][c] === EMPTY) {
        ownDist[nidx] = d + 1;
        queue[tail++] = nidx;
        reachable.push(nidx);
      }
    }
    if (r + 1 < size) {
      const nidx = idx + size;
      if (ownDist[nidx] === -1 && grid[r + 1][c] === EMPTY) {
        ownDist[nidx] = d + 1;
        queue[tail++] = nidx;
        reachable.push(nidx);
      }
    }
    if (c > 0) {
      const nidx = idx - 1;
      if (ownDist[nidx] === -1 && grid[r][c - 1] === EMPTY) {
        ownDist[nidx] = d + 1;
        queue[tail++] = nidx;
        reachable.push(nidx);
      }
    }
    if (c + 1 < size) {
      const nidx = idx + 1;
      if (ownDist[nidx] === -1 && grid[r][c + 1] === EMPTY) {
        ownDist[nidx] = d + 1;
        queue[tail++] = nidx;
        reachable.push(nidx);
      }
    }
  }

  if (reachable.length === 0) return [];

  if (enemySeeds.length > 0) {
    head = 0;
    tail = 0;
    for (let i = 0; i < enemySeeds.length; i++) {
      queue[tail] = enemySeeds[i];
      queueMeta[tail] = enemySeedIds[i];
      tail++;
    }
    while (head < tail) {
      const idx = queue[head];
      const srcId = queueMeta[head];
      head++;
      const d = enemyDist[idx];
      const r = (idx / size) | 0;
      const c = idx - r * size;

      if (r > 0) {
        const nidx = idx - size;
        if (enemyDist[nidx] === -1 && grid[r - 1][c] === EMPTY) {
          enemyDist[nidx] = d + 1;
          nearestEnemyId[nidx] = srcId;
          queue[tail] = nidx;
          queueMeta[tail] = srcId;
          tail++;
        }
      }
      if (r + 1 < size) {
        const nidx = idx + size;
        if (enemyDist[nidx] === -1 && grid[r + 1][c] === EMPTY) {
          enemyDist[nidx] = d + 1;
          nearestEnemyId[nidx] = srcId;
          queue[tail] = nidx;
          queueMeta[tail] = srcId;
          tail++;
        }
      }
      if (c > 0) {
        const nidx = idx - 1;
        if (enemyDist[nidx] === -1 && grid[r][c - 1] === EMPTY) {
          enemyDist[nidx] = d + 1;
          nearestEnemyId[nidx] = srcId;
          queue[tail] = nidx;
          queueMeta[tail] = srcId;
          tail++;
        }
      }
      if (c + 1 < size) {
        const nidx = idx + 1;
        if (enemyDist[nidx] === -1 && grid[r][c + 1] === EMPTY) {
          enemyDist[nidx] = d + 1;
          nearestEnemyId[nidx] = srcId;
          queue[tail] = nidx;
          queueMeta[tail] = srcId;
          tail++;
        }
      }
    }
  }

  // Estimate Voronoi-like territory: cells where we reach first
  let myVoronoi = 0;
  let contestedCells = 0;
  for (let i = 0; i < reachable.length; i++) {
    const idx = reachable[i];
    const od = ownDist[idx];
    const ed = enemyDist[idx];
    if (ed === -1 || od < ed) myVoronoi++;
    else if (od === ed) contestedCells++;
  }

  // Compute per-cell neighbor counts
  for (let i = 0; i < reachable.length; i++) {
    const idx = reachable[i];
    const r = (idx / size) | 0;
    const c = idx - r * size;
    let eN = 0, oN = 0, enN = 0;
    if (r > 0) {
      const v = grid[r-1][c];
      if (v === EMPTY) eN++;
      else if (v === id) oN++;
      else if (v !== null) enN++;
    }
    if (r+1 < size) {
      const v = grid[r+1][c];
      if (v === EMPTY) eN++;
      else if (v === id) oN++;
      else if (v !== null) enN++;
    }
    if (c > 0) {
      const v = grid[r][c-1];
      if (v === EMPTY) eN++;
      else if (v === id) oN++;
      else if (v !== null) enN++;
    }
    if (c+1 < size) {
      const v = grid[r][c+1];
      if (v === EMPTY) eN++;
      else if (v === id) oN++;
      else if (v !== null) enN++;
    }
    emptyNbr[idx] = eN;
    ownNbr[idx] = oN;
    enemyNbr[idx] = enN;
  }

  const progress = insideCount ? 1 - emptyCount / insideCount : 1;
  const center = (size - 1) / 2;
  const radius2 = center * center + 0.0001;

  // Detect if we're behind (losing the race)
  const totalClaimed = myCount + totalEnemies;
  const expectedShare = totalClaimed > 0 ? myCount / totalClaimed : 0.5;
  const aggression = expectedShare < 0.3 ? 1.4 : expectedShare < 0.5 ? 1.1 : 0.9;

  const centerWeight = progress < 0.2 ? 16 : progress < 0.5 ? 9 : progress < 0.8 ? 4 : 1;
  const depthWeight = progress < 0.3 ? 2.4 : progress < 0.7 ? 1.5 : 0.6;
  const stepPenalty = progress < 0.3 ? 0.6 : progress < 0.7 ? 1.2 : 2.2;
  const blockBonus = (progress < 0.6 ? 1.8 : 0.6) * aggression;

  const baseScore = new Float64Array(n);

  for (let i = 0; i < reachable.length; i++) {
    const idx = reachable[i];
    const r = (idx / size) | 0;
    const c = idx - r * size;

    const dr = r - center;
    const dc = c - center;
    let centrality = 1 - (dr * dr + dc * dc) / radius2;
    if (centrality < 0) centrality = 0;

    const od = ownDist[idx];
    const ed = enemyDist[idx];

    // Race scoring - more aggressive on winning cells
    let marginScore;
    if (ed === -1) {
      marginScore = 6;
    } else {
      const m = ed - od;
      if (m >= 5) marginScore = 22;
      else if (m === 4) marginScore = 19;
      else if (m === 3) marginScore = 16 * aggression;
      else if (m === 2) marginScore = 12 * aggression;
      else if (m === 1) marginScore = 8 * aggression;
      else if (m === 0) marginScore = -2;
      else if (m === -1) marginScore = -16;
      else marginScore = -26;
    }

    // Blocking the biggest enemy
    if (ed !== -1 && nearestEnemyId[idx] === biggestEnemy) {
      const m = ed - od;
      if (m >= 0 && m <= 3) marginScore += blockBonus * 3;
    }

    // Denial bonus: cells adjacent to enemies that we can claim first deny them 3 neighbors
    let denialBonus = 0;
    if (enemyNbr[idx] > 0) {
      // Being adjacent to enemy = chokepoint; claiming denies them
      if (ed !== -1 && od <= ed) denialBonus = 3.5 + 1.2 * enemyNbr[idx];
      else if (od <= 2) denialBonus = 2.0;
    }

    // Frontier value - expansion potential
    const frontierVal = 3.0 * emptyNbr[idx] - 2.8 * enemyNbr[idx] + 0.5 * ownNbr[idx];

    // Wall-building bonus: cells that block enemy advance
    let wallBonus = 0;
    if (ed !== -1 && ed - od <= 2 && emptyNbr[idx] >= 2) {
      wallBonus = 1.8;
    }

    baseScore[idx] =
      frontierVal +
      centerWeight * centrality +
      marginScore +
      denialBonus +
      wallBonus -
      stepPenalty * od;
  }

  // Greedy selection with bonus propagation
  const claimed = new Uint8Array(n);
  const moves = [];
  const bonus = new Float64Array(n);

  for (let step = 0; step < k; step++) {
    let bestIdx = -1;
    let bestScore = -1e15;

    for (let i = 0; i < reachable.length; i++) {
      const idx = reachable[i];
      if (claimed[idx]) continue;

      const r = (idx / size) | 0;
      const c = idx - r * size;

      let adjOwn = false;
      if (r > 0) {
        const nidx = idx - size;
        if (grid[r-1][c] === id || claimed[nidx]) adjOwn = true;
      }
      if (!adjOwn && r+1 < size) {
        const nidx = idx + size;
        if (grid[r+1][c] === id || claimed[nidx]) adjOwn = true;
      }
      if (!adjOwn && c > 0) {
        const nidx = idx - 1;
        if (grid[r][c-1] === id || claimed[nidx]) adjOwn = true;
      }
      if (!adjOwn && c+1 < size) {
        const nidx = idx + 1;
        if (grid[r][c+1] === id || claimed[nidx]) adjOwn = true;
      }
      if (!adjOwn) continue;

      const score = baseScore[idx] + bonus[idx] + depthWeight * ownDist[idx];

      if (score > bestScore) {
        bestScore = score;
        bestIdx = idx;
      }
    }

    if (bestIdx === -1) break;
    claimed[bestIdx] = 1;
    const br = (bestIdx / size) | 0;
    const bc = bestIdx - br * size;
    moves.push([br, bc]);

    // Propagate bonus to neighbors to encourage directional chains
    if (br > 0) bonus[bestIdx - size] += 2.0;
    if (br+1 < size) bonus[bestIdx + size] += 2.0;
    if (bc > 0) bonus[bestIdx - 1] += 2.0;
    if (bc+1 < size) bonus[bestIdx + 1] += 2.0;
  }

  const used = new Set(moves.map(m => m[0] * size + m[1]));
  const remaining = reachable
    .filter(idx => !used.has(idx))
    .sort((a, b) => (baseScore[b] + bonus[b]) - (baseScore[a] + bonus[a]))
    .map(idx => [(idx / size) | 0, idx % size]);

  return moves.concat(remaining);
}
