function myAlgorithm(id, grid, size) {
  const EMPTY = -1;
  const center = (size - 1) / 2;
  const radius = size / 2;

  // Find all my cells and frontier cells
  const frontier = []; // empty cells adjacent to mine
  const frontierSet = new Set();

  // Track enemy positions for threat assessment
  let enemyCells = 0;
  let myCells = 0;

  for (let r = 0; r < size; r++) {
    for (let c = 0; c < size; c++) {
      const v = grid[r][c];
      if (v === id) {
        myCells++;
      } else if (v !== null && v !== EMPTY && v !== id) {
        enemyCells++;
      }
    }
  }

  // Compute my centroid for directional bias
  let myR = 0, myC = 0;
  if (myCells > 0) {
    for (let r = 0; r < size; r++) {
      for (let c = 0; c < size; c++) {
        if (grid[r][c] === id) {
          myR += r;
          myC += c;
        }
      }
    }
    myR /= myCells;
    myC /= myCells;
  } else {
    myR = center;
    myC = center;
  }

  // Find frontier: empty cells adjacent to my cells
  const dirs = [[-1,0],[1,0],[0,-1],[0,1]];

  for (let r = 0; r < size; r++) {
    for (let c = 0; c < size; c++) {
      if (grid[r][c] !== EMPTY) continue;
      let adjMine = false;
      for (const [dr, dc] of dirs) {
        const nr = r + dr, nc = c + dc;
        if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
        if (grid[nr][nc] === id) {
          adjMine = true;
          break;
        }
      }
      if (adjMine) {
        const key = r * size + c;
        if (!frontierSet.has(key)) {
          frontierSet.add(key);
          frontier.push([r, c]);
        }
      }
    }
  }

  // Score each frontier cell
  const scored = frontier.map(([r, c]) => {
    let score = 0;

    // Count empty neighbors (expansion potential)
    let emptyNeighbors = 0;
    let enemyNeighbors = 0;
    let myNeighbors = 0;
    let nullNeighbors = 0;

    for (const [dr, dc] of dirs) {
      const nr = r + dr, nc = c + dc;
      if (nr < 0 || nr >= size || nc < 0 || nc >= size) {
        nullNeighbors++;
        continue;
      }
      const v = grid[nr][nc];
      if (v === null) nullNeighbors++;
      else if (v === EMPTY) emptyNeighbors++;
      else if (v === id) myNeighbors++;
      else enemyNeighbors++;
    }

    // Prefer cells with more empty neighbors (growth potential)
    score += emptyNeighbors * 10;

    // Block enemies - high priority to claim cells next to enemies
    score += enemyNeighbors * 15;

    // Avoid dead-ends (surrounded by walls/own)
    score -= nullNeighbors * 2;

    // Distance from center (prefer central territory early)
    const distFromCenter = Math.sqrt((r - center) ** 2 + (c - center) ** 2);

    // Early game: push toward center; late game: fill in
    const totalClaimed = myCells + enemyCells;
    const totalArea = Math.PI * radius * radius;
    const fillRatio = totalClaimed / totalArea;

    if (fillRatio < 0.3) {
      // Push outward from our centroid to claim new territory
      const distFromMyCenter = Math.sqrt((r - myR) ** 2 + (c - myC) ** 2);
      score += distFromMyCenter * 1.5;
      // Slight preference for center
      score -= distFromCenter * 0.3;
    } else {
      // Late game: prioritize blocking and filling
      score += enemyNeighbors * 10;
    }

    // Stay within circle (should already be handled)
    if (distFromCenter > radius - 0.5) {
      score -= 5;
    }

    return { cell: [r, c], score };
  });

  scored.sort((a, b) => b.score - a.score);

  return scored.map(s => s.cell);
}
