    let centrality = 1 - (dr * dr + dc * dc) / radius2;
    if (centrality < 0) centrality = 0;

    const od = ownDist[idx];
    const ed = enemyDist[idx];

    let marginScore;
    if (ed === -1) {
      marginScore = 3;
    } else {
      const m = ed - od;
      if (m >= 4) marginScore = 16 + 2 * Math.min(5, m - 4);
      else if (m === 3) marginScore = 13;
      else if (m === 2) marginScore = 9;
      else if (m === 1) marginScore = 5;
      else if (m === 0) marginScore = -8;
      else if (m === -1) marginScore = -17;
      else marginScore = -23 - 2 * Math.min(5, -m - 2);
    }

    let regionScore = 0.35 * Math.sqrt(S) + 0.35 * Math.min(20, S / (ourB + 1));
    if (enB === 0) {
      regionScore -= safePenalty;
    } else {
      regionScore += 1.2 * Math.min(8, (2 * (ourB + 1)) / (enB + 1));
    }

    baseScore[idx] =
      regionScore +
      2.0 * emptyNbr[idx] +
      0.9 * ownNbr[idx] -
      3.0 * enemyNbr[idx] +
      centerWeight * centrality +
      marginScore;
  }

  const NEG = -1e15;
  const bestByRem = new Array(k + 1);

  let arr = new Float64Array(n);
  arr.fill(NEG);
  for (let i = 0; i < reachable.length; i++) {
    const idx = reachable[i];
    arr[idx] = baseScore[idx];
  }
  bestByRem[1] = arr;

  for (let rem = 2; rem <= k; rem++) {
    const prev = bestByRem[rem - 1];
    const curArr = new Float64Array(n);
    curArr.fill(NEG);

    for (let i = 0; i < reachable.length; i++) {
      const idx = reachable[i];
      curArr[idx] = baseScore[idx];
    }

    for (let i = reachable.length - 1; i >= 0; i--) {
      const idx = reachable[i];
      const d = ownDist[idx];
      let best = curArr[idx];

      const r = (idx / size) | 0;
      const c = idx - r * size;

      if (r > 0) {
        const nidx = idx - size;
        if (ownDist[nidx] === d + 1) {
          const cand = prev[nidx] - stepPenalty;
          if (cand > best) best = cand;
        }
      }
      if (r + 1 < size) {
        const nidx = idx + size;
        if (ownDist[nidx] === d + 1) {
          const cand = prev[nidx] - stepPenalty;
          if (cand > best) best = cand;
        }
      }
      if (c > 0) {
        const nidx = idx - 1;
        if (ownDist[nidx] === d + 1) {
          const cand = prev[nidx] - stepPenalty;
          if (cand > best) best = cand;
        }
      }
      if (c + 1 < size) {
        const nidx = idx + 1;
        if (ownDist[nidx] === d + 1) {
          const cand = prev[nidx] - stepPenalty;
          if (cand > best) best = cand;
        }
      }

      curArr[idx] = best;
    }

    bestByRem[rem] = curArr;
  }

  const claimed = new Uint8Array(n);
  const moves = [];

  for (let step = 0; step < k; step++) {
    const rem = k - step;
    let bestIdx = -1;
    let bestScoreNow = NEG;

    for (let i = 0; i < reachable.length; i++) {
      const idx = reachable[i];
      if (claimed[idx]) continue;

      const r = (idx / size) | 0;
      const c = idx - r * size;

      let support = 0;
      let front = 0;

      if (r > 0) {
        const nidx = idx - size;
        const v = grid[r - 1][c];
        if (v === id || claimed[nidx]) support++;
        else if (v === EMPTY && !claimed[nidx]) front++;
      }
      if (r + 1 < size) {
        const nidx = idx + size;
        const v = grid[r + 1][c];
        if (v === id || claimed[nidx]) support++;
        else if (v === EMPTY && !claimed[nidx]) front++;
      }
      if (c > 0) {
        const nidx = idx - 1;
        const v = grid[r][c - 1];
        if (v === id || claimed[nidx]) support++;
        else if (v === EMPTY && !claimed[nidx]) front++;
      }
      if (c + 1 < size) {
        const nidx = idx + 1;
        const v = grid[r][c + 1];
        if (v === id || claimed[nidx]) support++;
        else if (v === EMPTY && !claimed[nidx]) front++;
      }

      if (support === 0) continue;

      let score =
        bestByRem[rem][idx] +
        depthWeight * ownDist[idx] +
        1.0 * support +
        0.6 * front;

      const ed = enemyDist[idx];
      if (ed !== -1 && ed <= ownDist[idx]) {
        score -= rem > 1 ? 4 : 2;
      }

      if (score > bestScoreNow) {
        bestScoreNow = score;
        bestIdx = idx;
      }
    }

    if (bestIdx === -1) break;
    claimed[bestIdx] = 1;
    moves.push([(bestIdx / size) | 0, bestIdx % size]);
  }

  return moves;
}
